import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import Navbar from '../components/Navbar';
import { superAdminAPI } from '../services/api';
import { toast } from 'react-toastify';

const SuperAdminDashboard = () => {
  return (
    <div>
      <Navbar title="Super Admin Dashboard" />
      <div style={styles.container}>
        <Sidebar />
        <div style={styles.content}>
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/admins" element={<ManageAdmins />} />
            <Route path="/companies" element={<ManageCompanies />} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

const Sidebar = () => {
  const location = useLocation();
  
  const menuItems = [
    { path: '/superadmin', label: 'Dashboard', icon: '📊' },
    { path: '/superadmin/admins', label: 'Manage Admins', icon: '👤' },
    { path: '/superadmin/companies', label: 'Manage Companies', icon: '🏢' },
  ];

  return (
    <div style={styles.sidebar}>
      {menuItems.map((item) => (
        <Link
          key={item.path}
          to={item.path}
          style={{
            ...styles.menuItem,
            backgroundColor: location.pathname === item.path ? '#3498db' : 'transparent',
            color: location.pathname === item.path ? 'white' : '#333',
          }}
        >
          <span>{item.icon}</span> {item.label}
        </Link>
      ))}
    </div>
  );
};

const DashboardHome = () => {
  const [stats, setStats] = useState({ admins: 0, companies: 0 });

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const [adminsRes, companiesRes] = await Promise.all([
        superAdminAPI.getAllAdmins(),
        superAdminAPI.getAllCompanies(),
      ]);
      setStats({
        admins: adminsRes.data.length,
        companies: companiesRes.data.length,
      });
    } catch (error) {
      toast.error('Failed to load statistics');
    }
  };

  return (
    <div>
      <h2 style={styles.pageTitle}>Dashboard Overview</h2>
      <div style={styles.statsGrid}>
        <div style={{...styles.statCard, backgroundColor: '#3498db'}}>
          <h3 style={styles.statNumber}>{stats.admins}</h3>
          <p>Total Admins</p>
        </div>
        <div style={{...styles.statCard, backgroundColor: '#27ae60'}}>
          <h3 style={styles.statNumber}>{stats.companies}</h3>
          <p>Total Companies</p>
        </div>
      </div>
    </div>
  );
};

const ManageAdmins = () => {
  const [admins, setAdmins] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    email: '',
    fullName: '',
    companyId: '',
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [adminsRes, companiesRes] = await Promise.all([
        superAdminAPI.getAllAdmins(),
        superAdminAPI.getAllCompanies(),
      ]);
      setAdmins(adminsRes.data);
      setCompanies(companiesRes.data);
    } catch (error) {
      toast.error('Failed to load data');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await superAdminAPI.createAdmin({
        ...formData,
        role: 'ADMIN',
        companyId: formData.companyId || null,
      });
      toast.success('Admin created successfully');
      setShowForm(false);
      setFormData({ username: '', password: '', email: '', fullName: '', companyId: '' });
      loadData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create admin');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this admin?')) return;
    try {
      await superAdminAPI.deleteAdmin(id);
      toast.success('Admin deleted successfully');
      loadData();
    } catch (error) {
      toast.error('Failed to delete admin');
    }
  };

  const handleMapCompany = async (adminId, companyId) => {
    try {
      await superAdminAPI.mapAdminToCompany(adminId, companyId);
      toast.success('Admin mapped to company successfully');
      loadData();
    } catch (error) {
      toast.error('Failed to map admin to company');
    }
  };

  return (
    <div>
      <div style={styles.header}>
        <h2 style={styles.pageTitle}>Manage Admins</h2>
        <button style={styles.addBtn} onClick={() => setShowForm(!showForm)}>
          {showForm ? 'Cancel' : '+ Add Admin'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} style={styles.formContainer}>
          <h3 style={styles.sectionTitle}>👤 Admin Details</h3>
          <div style={styles.formGrid}>
            <div style={styles.formField}>
              <label style={styles.label}>Username *</label>
              <input
                type="text"
                placeholder="Enter username"
                value={formData.username}
                onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Password *</label>
              <input
                type="password"
                placeholder="Enter password"
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Email *</label>
              <input
                type="email"
                placeholder="Enter email address"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Full Name *</label>
              <input
                type="text"
                placeholder="Enter full name"
                value={formData.fullName}
                onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Company *</label>
              <select
                value={formData.companyId}
                onChange={(e) => setFormData({ ...formData, companyId: e.target.value })}
                style={styles.input}
                required
              >
                <option value="">Select Company</option>
                {companies.map((c) => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>
          </div>
          <button type="submit" style={styles.submitBtn}>Create Admin</button>
        </form>
      )}

      <table style={styles.table}>
        <thead>
          <tr>
            <th style={styles.th}>ID</th>
            <th style={styles.th}>Username</th>
            <th style={styles.th}>Full Name</th>
            <th style={styles.th}>Email</th>
            <th style={styles.th}>Company</th>
            <th style={styles.th}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {admins.map((admin) => (
            <tr key={admin.id}>
              <td style={styles.td}>{admin.id}</td>
              <td style={styles.td}>{admin.username}</td>
              <td style={styles.td}>{admin.fullName}</td>
              <td style={styles.td}>{admin.email}</td>
              <td style={styles.td}>
                {admin.company ? (
                  admin.company.name
                ) : (
                  <select
                    onChange={(e) => handleMapCompany(admin.id, e.target.value)}
                    style={styles.selectSmall}
                  >
                    <option value="">Assign Company</option>
                    {companies.map((c) => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                )}
              </td>
              <td style={styles.td}>
                <button style={styles.deleteBtn} onClick={() => handleDelete(admin.id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const ManageCompanies = () => {
  const [companies, setCompanies] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    logoUrl: '',
    address: '',
    phone: '',
    email: '',
  });

  useEffect(() => {
    loadCompanies();
  }, []);

  const loadCompanies = async () => {
    try {
      const res = await superAdminAPI.getAllCompanies();
      setCompanies(res.data);
    } catch (error) {
      toast.error('Failed to load companies');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await superAdminAPI.createCompany(formData);
      toast.success('Company created successfully');
      setShowForm(false);
      setFormData({ name: '', logoUrl: '', address: '', phone: '', email: '' });
      loadCompanies();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create company');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this company?')) return;
    try {
      await superAdminAPI.deleteCompany(id);
      toast.success('Company deleted successfully');
      loadCompanies();
    } catch (error) {
      toast.error('Failed to delete company');
    }
  };

  return (
    <div>
      <div style={styles.header}>
        <h2 style={styles.pageTitle}>Manage Companies</h2>
        <button style={styles.addBtn} onClick={() => setShowForm(!showForm)}>
          {showForm ? 'Cancel' : '+ Add Company'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} style={styles.form}>
          <input
            type="text"
            placeholder="Company Name"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            style={styles.input}
            required
          />
          <input
            type="text"
            placeholder="Logo URL (optional)"
            value={formData.logoUrl}
            onChange={(e) => setFormData({ ...formData, logoUrl: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Address"
            value={formData.address}
            onChange={(e) => setFormData({ ...formData, address: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Phone"
            value={formData.phone}
            onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
            style={styles.input}
          />
          <input
            type="email"
            placeholder="Email"
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
            style={styles.input}
          />
          <button type="submit" style={styles.submitBtn}>Create Company</button>
        </form>
      )}

      <table style={styles.table}>
        <thead>
          <tr>
            <th style={styles.th}>ID</th>
            <th style={styles.th}>Name</th>
            <th style={styles.th}>Logo</th>
            <th style={styles.th}>Address</th>
            <th style={styles.th}>Phone</th>
            <th style={styles.th}>Email</th>
            <th style={styles.th}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {companies.map((company) => (
            <tr key={company.id}>
              <td style={styles.td}>{company.id}</td>
              <td style={styles.td}>{company.name}</td>
              <td style={styles.td}>
                {company.logoUrl ? (
                  <img src={company.logoUrl} alt="Logo" style={styles.logo} />
                ) : (
                  <span style={styles.noLogo}>No Logo</span>
                )}
              </td>
              <td style={styles.td}>{company.address || '-'}</td>
              <td style={styles.td}>{company.phone || '-'}</td>
              <td style={styles.td}>{company.email || '-'}</td>
              <td style={styles.td}>
                <button style={styles.deleteBtn} onClick={() => handleDelete(company.id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    minHeight: 'calc(100vh - 70px)',
  },
  sidebar: {
    width: '250px',
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRight: '1px solid #dee2e6',
  },
  menuItem: {
    display: 'block',
    padding: '12px 15px',
    borderRadius: '5px',
    textDecoration: 'none',
    marginBottom: '5px',
    transition: 'all 0.3s',
  },
  content: {
    flex: 1,
    padding: '30px',
    backgroundColor: '#f5f6fa',
  },
  pageTitle: {
    marginBottom: '20px',
    color: '#2c3e50',
  },
  statsGrid: {
    display: 'flex',
    gap: '20px',
  },
  statCard: {
    padding: '30px',
    borderRadius: '10px',
    color: 'white',
    minWidth: '200px',
    textAlign: 'center',
  },
  statNumber: {
    fontSize: '36px',
    margin: '0 0 10px 0',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
